import { useState } from "react";

const FRAMEWORKS = ["NIST SP 800-53", "NIST CSF 2.0", "FedRAMP", "CIS Controls v8"];
const ENVS = ["AWS", "Azure", "GCP", "Multi-cloud"];

export default function App() {
  const [input, setInput] = useState("");
  const [env, setEnv] = useState("AWS");
  const [framework, setFramework] = useState("NIST SP 800-53");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  async function assess() {
    setError(""); setResult(null); setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": process.env.REACT_APP_ANTHROPIC_API_KEY,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true"
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 4000,
          system: `You are a senior GRC analyst for ${env} environments using ${framework}. Return ONLY valid JSON (no markdown) with keys: assessmentQuestions (array), evidenceToCollect (array), potentialWeaknesses (array of {name, description, severity}), nistControls (array of {id, name, rationale}). Be specific to ${env}.`,
          messages: [{ role: "user", content: `Assess this security control:\n\n${input}` }]
        })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const text = data.content.find(b => b.type === "text")?.text || "";
      setResult(JSON.parse(text.replace(/```json|```/g, "").trim()));
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }

  return (
    <div style={{ minHeight: "100vh", background: "#0f1117", color: "#e2e8f0", fontFamily: "system-ui, sans-serif", padding: "2rem 1rem" }}>
      <div style={{ maxWidth: 760, margin: "0 auto" }}>
        <span style={{ fontSize: 11, background: "#1e3a5f", color: "#60a5fa", padding: "3px 10px", borderRadius: 99, fontWeight: 600, letterSpacing: "0.05em" }}>
          GRC PORTFOLIO TOOL
        </span>
        <h1 style={{ fontSize: 28, fontWeight: 700, margin: "0.75rem 0 0.25rem", color: "#f1f5f9" }}>
          Security Control Assessor
        </h1>
        <p style={{ color: "#64748b", marginBottom: "1.75rem", fontSize: 14 }}>
          Powered by Claude AI · Assessment questions, evidence checklists, weaknesses & {framework} mappings
        </p>

        <div style={{ background: "#1a1d27", border: "1px solid #2d3748", borderRadius: 12, padding: "1.25rem", marginBottom: "1rem" }}>
          <label style={{ fontSize: 12, fontWeight: 600, color: "#94a3b8", display: "block", marginBottom: 8, letterSpacing: "0.05em" }}>
            CONTROL DESCRIPTION OR SYSTEM DETAIL
          </label>
          <textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            placeholder="Example: Our AWS environment uses IAM roles with least-privilege for EC2. MFA is enforced on root and all IAM users..."
            style={{ width: "100%", minHeight: 130, padding: "0.75rem", borderRadius: 8, border: "1px solid #2d3748", fontSize: 14, resize: "vertical", fontFamily: "inherit", boxSizing: "border-box", background: "#0f1117", color: "#e2e8f0" }}
          />
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginTop: 10 }}>
            <div>
              <label style={{ fontSize: 11, color: "#64748b", display: "block", marginBottom: 4, letterSpacing: "0.05em" }}>CLOUD ENVIRONMENT</label>
              <select value={env} onChange={e => setEnv(e.target.value)}
                style={{ width: "100%", padding: "0.5rem 0.75rem", borderRadius: 8, border: "1px solid #2d3748", fontSize: 13, background: "#0f1117", color: "#e2e8f0" }}>
                {ENVS.map(e => <option key={e}>{e}</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize: 11, color: "#64748b", display: "block", marginBottom: 4, letterSpacing: "0.05em" }}>COMPLIANCE FRAMEWORK</label>
              <select value={framework} onChange={e => setFramework(e.target.value)}
                style={{ width: "100%", padding: "0.5rem 0.75rem", borderRadius: 8, border: "1px solid #2d3748", fontSize: 13, background: "#0f1117", color: "#e2e8f0" }}>
                {FRAMEWORKS.map(f => <option key={f}>{f}</option>)}
              </select>
            </div>
          </div>
          <button onClick={assess} disabled={loading || !input.trim()}
            style={{ width: "100%", marginTop: 12, padding: "0.7rem", borderRadius: 8, border: "none", background: loading ? "#1e3a5f" : "#2563eb", color: loading ? "#60a5fa" : "#fff", fontSize: 14, fontWeight: 600, cursor: loading ? "not-allowed" : "pointer", transition: "background 0.2s" }}>
            {loading ? "⏳ Analyzing..." : "⚡ Assess control"}
          </button>
        </div>

        {error && <div style={{ background: "#2d1515", border: "1px solid #7f1d1d", borderRadius: 8, padding: "0.75rem 1rem", color: "#f87171", fontSize: 13, marginBottom: "1rem" }}>{error}</div>}

        {result && <Results result={result} framework={framework} />}
      </div>
    </div>
  );
}

function Results({ result, framework }) {
  const sevColor = s => s === "High" ? ["#2d1515","#f87171","#7f1d1d"] : s === "Medium" ? ["#2d2006","#fbbf24","#78350f"] : ["#0f2d1a","#4ade80","#14532d"];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      <Card icon="❓" title="Assessment questions" accent="#2563eb">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.assessmentQuestions.map((q, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#cbd5e1" }}>{q}</li>)}
        </ul>
      </Card>
      <Card icon="📋" title="Evidence to collect" accent="#0891b2">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.evidenceToCollect.map((e, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#cbd5e1" }}>{e}</li>)}
        </ul>
      </Card>
      <Card icon="⚠️" title="Potential weaknesses" accent="#dc2626">
        {result.potentialWeaknesses.map((w, i) => {
          const [bg, tc, border] = sevColor(w.severity);
          return <div key={i} style={{ padding: "0.75rem 0", borderBottom: i < result.potentialWeaknesses.length - 1 ? "1px solid #1e2433" : "none" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
              <span style={{ fontSize: 13, fontWeight: 600, color: "#f1f5f9" }}>{w.name}</span>
              <span style={{ fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 99, background: bg, color: tc, border: `1px solid ${border}`, marginLeft: "auto" }}>{w.severity}</span>
            </div>
            <p style={{ fontSize: 12, color: "#64748b", lineHeight: 1.6, margin: 0 }}>{w.description}</p>
          </div>;
        })}
      </Card>
      <Card icon="📖" title={`${framework} control mappings`} accent="#7c3aed">
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 12 }}>
          {result.nistControls.map((c, i) => <span key={i} style={{ fontSize: 12, fontFamily: "monospace", padding: "3px 10px", borderRadius: 99, background: "#1e1a2e", border: "1px solid #4c1d95", color: "#a78bfa" }}>{c.id}</span>)}
        </div>
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.nistControls.map((c, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#cbd5e1" }}><strong style={{ color: "#f1f5f9" }}>{c.id} – {c.name}:</strong> {c.rationale}</li>)}
        </ul>
      </Card>
    </div>
  );
}

function Card({ icon, title, accent, children }) {
  return (
    <div style={{ background: "#1a1d27", border: "1px solid #2d3748", borderRadius: 12, overflow: "hidden" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "0.85rem 1.25rem", borderBottom: "1px solid #2d3748", borderLeft: `3px solid ${accent}` }}>
        <span style={{ fontSize: 16 }}>{icon}</span>
        <span style={{ fontSize: 13, fontWeight: 700, color: "#f1f5f9", letterSpacing: "0.02em" }}>{title.toUpperCase()}</span>
      </div>
      <div style={{ padding: "1rem 1.25rem" }}>{children}</div>
    </div>
  );
}
